              :disabled="boxItems.length === 0 || isAddingToCart"
            >
              {{ isAddingToCart ? '✓ Добавлено' : 'Добавить в корзину' }}
            </button>
            <button 
              class="button-gray montserrat-medium"
              @click="toggleFavorite"
              :title="isFavorite ? 'Убрать из избранного' : 'В избранное'"
            >
              {{ isFavorite ? '♥' : '♡' }}
            </button>
          </div>

          <!-- Теги -->
          <div class="tags-block">
            <span 
              v-for="tag in box.tags" 
              :key="tag"
              class="tag montserrat-regular"
            >
              {{ tag }}
            </span>
          </div>
        </div>
      </div>

