<script setup>
import { ref, computed, onMounted } from 'vue'
import { useRoute } from 'vue-router' // если используешь vue-router
import { boxes, calculateBoxPrice } from '@/data/boxes'
import {products} from '@/data/products'
import Card from "@/components/Card.vue"
import { cartUtils } from '@/utils/cartUtils'
import { favoritesUtils } from '@/utils/favoritesUtils'

// Получить slug из роута (или пропсов)
const props = defineProps({
  boxId: String, // если передаёшь напрямую
  slug: String   // если используешь slug
})

const route = useRoute() // раскомментируй если используешь vue-router
const slug = computed(() => props.slug || route.params.slug)

const currentImage = ref('')
const isFavorite = ref(false)
const isAddingToCart = ref(false)

// Найти бокс по slug или id
const box = computed(() => {
  return boxes.find(b => b.slug === slug.value || b.id === props.boxId)
})

const similarBoxes = computed(() => {
  if (!box.value) return []

  // убираем текущий бокс
  const others = boxes.filter(b => b.id !== box.value.id)

  // ищем боксы с той же эмоцией или пересечением тегов
  let similar = others.filter(b => {
    const sameEmotion = b.emotion === box.value.emotion
    const sameTag = b.tags.some(tag => box.value.tags.includes(tag))
    return sameEmotion || sameTag
  })

  // если нашлось меньше 4 — добиваем случайными
  if (similar.length < 4) {
    const rest = others.filter(b => !similar.includes(b))
    // перемешиваем
    for (let i = rest.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1))
      ;[rest[i], rest[j]] = [rest[j], rest[i]]
    }
    similar = similar.concat(rest.slice(0, 4 - similar.length))
  }

  // если вообще нет похожих — просто 4 случайных
  if (similar.length === 0) {
    const shuffled = [...others].sort(() => 0.5 - Math.random())
    return shuffled.slice(0, 4)
  }

  return similar.slice(0, 4)
})
// Состав бокса (редактируемый)
const boxItems = ref([])

// Оригинальная цена (дефолтный состав)
const originalPrice = computed(() => {
  if (!box.value) return 0
  return calculateBoxPrice(box.value.id)
})

// Текущая цена (с учётом изменений)
const totalPrice = computed(() => {
  return boxItems.value.reduce((sum, item) => {
    return sum + (item.price * item.quantity)
  }, 0)
})

// Проверка, изменён ли состав
const isCompositionModified = computed(() => {
  if (!box.value) return false
  
  const original = box.value.defaultComposition
  if (original.length !== boxItems.value.length) return true
  
  return boxItems.value.some(item => {
    const originalItem = original.find(o => o.productId === item.productId)
    return !originalItem || originalItem.quantity !== item.quantity
  })
})

// Увеличить количество
function increaseQuantity(item) {
  item.quantity++
}

// Уменьшить количество
function decreaseQuantity(item) {
  if (item.quantity > 1) {
    item.quantity--
  }
}

// Удалить товар
function removeItem(productId) {
  boxItems.value = boxItems.value.filter(item => item.productId !== productId)
}

// Сбросить к оригинальному составу
function resetComposition() {
  if (!box.value) return
  loadBoxComposition()
}

// Загрузить состав бокса
function loadBoxComposition() {
  if (!box.value) return
  
  boxItems.value = box.value.defaultComposition.map(item => {
    const product = products[item.productId]
    return {
      productId: item.productId,
      name: product.name,
      description: product.description,
      price: product.price,
      image: product.image,
      quantity: item.quantity
    }
  })
}

// Добавить в корзину
function addToCart() {
  if (!box.value || boxItems.value.length === 0) return
  
  isAddingToCart.value = true
  
  // Создаём кастомный состав если он изменён
  const customComposition = isCompositionModified.value
    ? boxItems.value.map(item => ({
        productId: item.productId,
        quantity: item.quantity
      }))
    : null
  
  // Если состав не изменён, добавляем дефолтный бокс
  if (!customComposition) {
    cartUtils.addBox(box.value.id)
  } else {
    // Если изменён, добавляем с кастомным составом
    const cartItem = cartUtils.addBox(box.value.id)
    cartUtils.updateBoxComposition(cartItem.id, customComposition)
  }
  
  console.log('Добавлено в корзину:', box.value.name, customComposition ? '(изменённый состав)' : '')
  
  setTimeout(() => {
    isAddingToCart.value = false
  }, 2000)
}

// Переключить избранное
function toggleFavorite() {
  if (!box.value) return
  const added = favoritesUtils.toggle(box.value.id)
  isFavorite.value = added
}

// Форматировать цену
function formatPrice(price) {
  return price.toLocaleString('ru-RU')
}

// Инициализация
onMounted(() => {
  if (box.value) {
    currentImage.value = box.value.images[0]
    isFavorite.value = favoritesUtils.isFavorite(box.value.id)
    loadBoxComposition()
  }
})
</script>

